% make sure previously defined variables are erased. clear;   
% read a spreadsheet named "IGE.xls" into MATLAB. [num, txt] $=$ xlsread(\`IGE');   
$\%$ the first column (starting from the second row) % contains the trading days in format mm/dd/yyyy. tday $=$ txt(2:end, 1);   
% convert the format into yyyymmdd.   
tday $=$ datestr(datenum(tday, \`mm/dd/yyyy'), \`yyyymmdd'); $\%$ convert the date strings first into cell arrays and % then into numeric format.   
tday $=$ str2double(cellstr(tday));   
% the last column contains the adjusted close prices. cls $=$ num(:, end);   
% sort tday into ascending order.   
[tday sortIndex] $=$ sort(tday, \`ascend');   
% sort cls into ascending order of dates.   
$_ { \mathsf { C } } 1 { \mathsf { s } } { = } { \mathsf { C } } 1 { \mathsf { s } }$ (sortIndex);   
% daily returns   
dailyret $=$ (cls(2:end)-cls(1:end-1))./cls(1:end-1); % excess daily returns assuming risk-free rate of 4% % per annum and 252 trading days in a year   
excessRet $=$ dailyret - 0.04/252;   
% the output should be 0.7893   
sharpeRatio $=$ sqrt(252)\*mean(excessRet)/std(excessRet)

function [maxDD maxDDD] $=$ calculateMaxDD(cumret)   
% [maxDD maxDDD] $=$ calculateMaxDD(cumret)   
% calculation of maximum drawdown and maximum drawdown % duration based on cumulative compounded returns. % initialize high watermarks to zero.   
highwatermark $\underline { { \underline { { \mathbf { \Pi } } } } } =$ zeros(size(cumret));   
$\%$ initialize drawdowns to zero.   
drawdown $=$ zeros(size(cumret));   
$\%$ initialize drawdown duration to zero.   
drawdownduration $=$ zeros(size(cumret));   
for ${ \tt = } 2$ :length(cumret)   
highwatermark $( \ t ) = \dots$   
max(highwatermark(t-1), cumret(t));   
$\%$ drawdown on each day   
drawdown $( \ t ) = ( 1 +$ cumret(t))/( $^ { 1 + }$ highwatermark(t))-1; if (drawdown(t) $\scriptstyle = = 0$ ) drawdownduration $( \ t ) = 0$ ; else drawdownduration(t) $=$ drawdownduration(t-1) $^ { + 1 }$ ; end   
end   
maxDD $=$ max(drawdown); % maximum drawdown   
% maximum drawdown duration   
maxDDD $=$ max(drawdownduration);

# calculateMaxDD.R   
calculateMaxDD <- function(cumret) { # Assume compounded cumulative return as input highwatermark <- rep(0, length(cumret)) highwatermark drawdown <- rep(0, length(cumret)) drawdownduration $< -$ rep(0, length(cumret)) for (t in 2:length(cumret)) { highwatermark[t] $< -$ max(highwatermark[t-1], cumret[t]) drawdown[t] $< -$ ( $^ { 1 + }$ cumret[t])/(1+highwatermark[t])-1 if (drawdown[t] $\scriptstyle = = 0$ ) { drawdownduration $[ \ t ] = 0$   
} else { drawdownduration[t] $=$ drawdownduration[t-1]+1   
}   
}   
maxDD <- min(drawdown)   
maxDDD $< -$ max(drawdownduration)   
return(c(maxDD, maxDDD))   
}

