function $\begin{array} { r l } { \mathrm { y } } & { { } = } \end{array}$ smartsum(x, dim)   
$\begin{array} { l l } { \frac { \mathrm { ~ \circ ~ } } { \mathrm { ~ \circ ~ } } \mathsf { y } } & { = } \end{array}$ smartsum(x, dim)   
%Sum along dimension dim, ignoring NaN.   
hasData $=$ isfinite(x);   
x(\~hasData) $= 0$ ;   
y=sum(x,dim);   
y(all(\~hasData, dim)) $= \tt N a N$ ;   
