function $\begin{array} { r l } { \mathrm { y } } & { { } = } \end{array}$ smartmean(x, dim)   
$\%$ y = smartmean(x, dim)   
% Mean value along dimension dim, ignoring NaN.   
hasData $\underline { { \underline { { \mathbf { \Pi } } } } } =$ isfinite(x);   
x(\~hasData) $= 0$ ;   
y=sum(x,dim)./sum(hasData, dim);   
y(all(\~hasData, dim)) $= \tt N a N$ ; % set y to NaN if all entries are NaNs.   
